import{_ as a,o as b,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"灵马托雷特","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/1.D级/灵马托雷特.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/1.D级/灵马托雷特.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/载具/1.D级/灵马托雷特.md"};function o(d,e,_,l,i,c){return b(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"灵马托雷特",tabindex:"-1"},[p("灵马托雷特 "),r("a",{class:"header-anchor",href:"#灵马托雷特","aria-label":'Permalink to "灵马托雷特"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调016")])])],-1),n('<h1 id="灵马托雷特-1" tabindex="-1">灵马托雷特 <a class="header-anchor" href="#灵马托雷特-1" aria-label="Permalink to &quot;灵马托雷特&quot;">​</a></h1><p>灵马托雷特<br> 本兑换是出自《艾尔登法环》世界中的灵马托雷特，虽然名称是马，但是头顶生有宛如牛类一般的角，同时还能够进行二段的跳跃，协助褪色者跨越险峻的地形。<br> 本兑换不会附赠载具通用的空间胶囊，作为代替，会赠送一枚戒指，只要消耗一个迅捷动作，就可以将灵马托雷特召唤出来，供自己骑乘。</p><p>价格：D+500<br> ▓▓▓▓基本能力值<br> ▓智力 2<br> ▓感知 4<br> ▓决心 4</p><p>▓力量 6<br> ▓敏捷 6<br> ▓耐力 4</p><p>▓风度 6<br> ▓操控 2<br> ▓沉着 4</p><p>▓▓▓▓技能<br> ▓知识1<br> ▓器用1<br> ▓手艺1<br> ▓专注3-意志3</p><p>▓运动5-反射3 跳跃5<br> ▓生存5-强韧5 追踪3<br> ▓射击1<br> ▓武技3-角3</p><p>▓洞察3-侦查3<br> ▓隐秘3<br> ▓表达1<br> ▓社交1</p><p>▓▓▓▓衍生属性值<br> ▓相貌:6<br> ▓体积 5<br> ▓速度 力量6+敏捷6+敏捷附加3+体积5+灵马55=75<br> ▓先攻10<br> ▓防御 基础4+1<br> ▓生命值9<br> ▓意志力池8<br> ▓意志8<br> ▓反射14+3<br> ▓强韧14+2<br> ▓察言观色10<br> ▓侦查10+1<br> ▓跳跃19+5<br> ▓敏感范围 80<br> ▓▓▓▓攻击预设：<br> 力量6+武技3+角3+增强3+天生武器1=16+1<br> ▓▓▓▓防御预设：<br> 基防4+1</p><p>特性：<br> 【灵马】 ：托雷特并非普通的马匹，因而它的移动速度提升55米，并且全身视为具有1L的天生武器伤害。<br> 【二段跳】 ：托雷特在进行跳跃时，可以在空中借力一次，因此托雷特进行的跳跃检定额外具有2点附加成功。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
